import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { getImageUrl, PLACEHOLDER_IMG } from '../shared/constants';
import PhotoGallery from './PhotoGallery';

const API_URL = process.env.REACT_APP_API_URL || '';

function ProviderPortfolio({ providerId, providerName, onClose }) {
  const resolvedProviderId = typeof providerId === 'object'
    ? (providerId?._id || providerId?.id || null)
    : providerId;

  const [profile, setProfile] = useState(null);
  const [error, setError] = useState('');
  const [completedJobs, setCompletedJobs] = useState([]);
  const [postedJobs, setPostedJobs] = useState([]);
  const [services, setServices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('work');
  const [workCategoryFilter, setWorkCategoryFilter] = useState('all');
  const [galleryPhotos, setGalleryPhotos] = useState([]);
  const [galleryStartIndex, setGalleryStartIndex] = useState(0);

  const token = localStorage.getItem('token');

  useEffect(() => {
    fetchProviderData();
  }, [resolvedProviderId]);

  const normalizeImages = (imgs) => {
    if (!Array.isArray(imgs)) return [];
    return imgs.map(img => (typeof img === 'string' ? { url: img } : img));
  };

  const asArray = (value) => Array.isArray(value) ? value : [];
  const safeCategory = (value) => (typeof value === 'string' ? value : '').trim();

  const fetchProviderData = async () => {
    try {
      setError('');
      if (!resolvedProviderId) {
        setError('Profile unavailable: missing provider ID.');
        setLoading(false);
        return;
      }

      const profileRes = await axios.get(`${API_URL}/api/users/${resolvedProviderId}`);
      setProfile(profileRes.data);

      const jobsRes = await axios.get(`${API_URL}/api/transactions/provider/${resolvedProviderId}/completed`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const transactionJobs = jobsRes.data || [];

      const portfolioRes = await axios.get(`${API_URL}/api/jobs/portfolio/${resolvedProviderId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const jobBoardData = portfolioRes.data || {};
      const jobBoardCompleted = (jobBoardData.completedJobs || []).map(job => ({
        _id: job._id,
        serviceId: { title: job.title, category: job.category },
        jobDescriptionImages: normalizeImages(job.images),
        proofImages: normalizeImages(job.workProofPhotos),
        completedAt: job.completedAt,
        randAmount: job.approvedAmount || job.budget,
        providerReview: job.providerReview,
        providerRating: job.providerRating,
        isJobBoard: true,
      }));

      setCompletedJobs([...transactionJobs, ...jobBoardCompleted]);
      setPostedJobs(jobBoardData.postedJobs || []);

      const servicesRes = await axios.get(`${API_URL}/api/services`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const servicesList = Array.isArray(servicesRes.data) ? servicesRes.data : [];
      const providerServices = servicesList.filter(s => String(s.providerId?._id || s.providerId) === String(resolvedProviderId));
      setServices(providerServices);
    } catch (err) {
      console.error('Failed to fetch provider data:', err);
      setError(err?.response?.data?.error || 'Failed to load provider profile');
    }
    setLoading(false);
  };

  const onlineStatus = () => {
    if (!profile) return 'gray';
    if (!profile.showOnlineStatus) return 'gray';
    if (profile.isOnline) return 'green';
    const lastActive = new Date(profile.lastActive);
    const minsAgo = (Date.now() - lastActive.getTime()) / 60000;
    return minsAgo < 30 ? 'yellow' : 'gray';
  };

  const statusColor = { green: '#22c55e', yellow: '#f59e0b', gray: '#9ca3af' };
  const statusText = { green: 'Online', yellow: 'Away', gray: 'Offline' };

  if (loading) {
    return (
      <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, zIndex: 10001 }}>
        <div style={{ background: 'white', borderRadius: 20, padding: 32 }}>
          <div style={{ fontSize: 20 }}>Loading profile... ⏳</div>
        </div>
      </div>
    );
  }

  const displayName = profile?.name || providerName || 'Community Member';
  const avatarUrl = profile?.profileImage || profile?.avatar;
  const initial = displayName[0]?.toUpperCase() || '?';
  const memberSince = profile?.createdAt
    ? new Date(profile.createdAt).toLocaleDateString('en-ZA', { month: 'short', year: 'numeric' })
    : null;
  const rating = Number(profile?.communityStats?.receivedRatingsAvg || profile?.rating || 0) || 0;
  const jobsDone = profile?.communityStats?.jobsCompleted || completedJobs.length || 0;
  const jobsPosted = profile?.communityStats?.jobsRequested || postedJobs.length || 0;
  const reliability = profile?.communityStats?.reliabilityScore ?? 100;

  const tabs = [
    { key: 'work', label: 'Work', count: completedJobs.length, icon: '📸' },
    { key: 'services', label: 'Services', count: services.length, icon: '💼' },
    { key: 'posted', label: 'Posted', count: postedJobs.length, icon: '📋' },
  ];

  const openGallery = (photos = [], startIndex = 0) => {
    const normalized = (photos || []).map(p => (typeof p === 'string' ? { url: p } : p)).filter(p => p && (p.url || p));
    if (!normalized.length) return;
    setGalleryPhotos(normalized);
    setGalleryStartIndex(startIndex);
  };

  const workCategories = ['all', ...Array.from(new Set(
    completedJobs
      .map(job => safeCategory(job.serviceId?.category || job.category || ''))
      .filter(Boolean)
  ))];

  const filteredCompletedJobs = completedJobs.filter(job => {
    if (workCategoryFilter === 'all') return true;
    const category = safeCategory(job.serviceId?.category || job.category || '');
    return category === workCategoryFilter;
  });

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'flex-end', justifyContent: 'center', zIndex: 10001 }}>
      <div style={{
        background: 'white', borderRadius: '24px 24px 0 0', width: '100%', maxWidth: 600,
        maxHeight: '90vh', display: 'flex', flexDirection: 'column', overflow: 'hidden',
        boxShadow: '0 -20px 60px rgba(0,0,0,0.3)'
      }}>

        {/* Drag handle */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '8px 16px', position: 'relative', flexShrink: 0 }}>
          <div style={{ width: 40, height: 5, borderRadius: 10, background: '#e2e8f0' }} />
          <button
            onClick={onClose}
            aria-label="Close profile"
            style={{
              position: 'absolute',
              top: 8,
              right: 16,
              width: 40,
              height: 40,
              borderRadius: '50%',
              border: '1px solid #e2e8f0',
              background: 'white',
              color: '#64748b',
              fontSize: 20,
              fontWeight: 700,
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            ✕
          </button>
        </div>

        {/* Compact Profile Header */}
        <div style={{ padding: '0 20px 16px', flexShrink: 0 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
            {/* Avatar */}
            <div style={{ position: 'relative', flexShrink: 0 }}>
              <div style={{
                width: 64, height: 64, borderRadius: 20, overflow: 'hidden',
                background: avatarUrl ? 'transparent' : 'linear-gradient(135deg, #6366f1, #4f46e5)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 24, color: 'white', fontWeight: 700,
                border: '3px solid #f1f5f9'
              }}>
                {avatarUrl ? (
                  <img src={avatarUrl} alt={displayName} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : initial}
              </div>
              <div style={{
                position: 'absolute', bottom: 2, right: 2, width: 14, height: 14,
                borderRadius: '50%', background: statusColor[onlineStatus()], border: '2.5px solid white'
              }} />
            </div>

            {/* Name + Info */}
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 800, color: '#1e293b' }}>{displayName}</h2>
                {profile?.verified && (
                  <span style={{ fontSize: 10, background: '#dbeafe', color: '#1d4ed8', padding: '2px 8px', borderRadius: 20, fontWeight: 700 }}>✓ Verified</span>
                )}
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 4, flexWrap: 'wrap' }}>
                <span style={{ fontSize: 13, color: '#64748b', fontWeight: 600 }}>{profile?.primaryCategory || 'Provider'}</span>
                {rating > 0 && (
                  <span style={{ fontSize: 13, color: '#f59e0b', fontWeight: 700 }}>⭐ {rating.toFixed(1)}</span>
                )}
                <span style={{ fontSize: 12, color: '#94a3b8' }}>{statusText[onlineStatus()]}</span>
              </div>
            </div>
          </div>

          {/* Quick Stats Grid */}
          <div style={{
            display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 8, marginTop: 14
          }}>
            <div style={{ background: '#f8fafc', borderRadius: 14, padding: '10px 4px', textAlign: 'center' }}>
              <div style={{ fontSize: 16, fontWeight: 800, color: '#1e293b' }}>{jobsDone}</div>
              <div style={{ fontSize: 10, color: '#94a3b8', fontWeight: 600, marginTop: 2 }}>Jobs Done</div>
            </div>
            <div style={{ background: '#f8fafc', borderRadius: 14, padding: '10px 4px', textAlign: 'center' }}>
              <div style={{ fontSize: 16, fontWeight: 800, color: '#1e293b' }}>{jobsPosted}</div>
              <div style={{ fontSize: 10, color: '#94a3b8', fontWeight: 600, marginTop: 2 }}>Posted</div>
            </div>
            <div style={{ background: '#f8fafc', borderRadius: 14, padding: '10px 4px', textAlign: 'center' }}>
              <div style={{ fontSize: 16, fontWeight: 800, color: '#1e293b' }}>{reliability}%</div>
              <div style={{ fontSize: 10, color: '#94a3b8', fontWeight: 600, marginTop: 2 }}>Reliable</div>
            </div>
            <div style={{ background: '#f8fafc', borderRadius: 14, padding: '10px 4px', textAlign: 'center' }}>
              <div style={{ fontSize: 16, fontWeight: 800, color: '#1e293b' }}>{memberSince || 'New'}</div>
              <div style={{ fontSize: 10, color: '#94a3b8', fontWeight: 600, marginTop: 2 }}>Member</div>
            </div>
          </div>

          {/* Skills */}
          {asArray(profile?.skills).length > 0 && (
            <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 12 }}>
              {asArray(profile?.skills).slice(0, 8).map((skill, i) => (
                <span key={i} style={{ fontSize: 11, background: '#eef2ff', color: '#4338ca', padding: '4px 10px', borderRadius: 20, fontWeight: 600 }}>{skill}</span>
              ))}
              {asArray(profile?.skills).length > 8 && (
                <span style={{ fontSize: 11, color: '#94a3b8', fontWeight: 600, padding: '4px 0' }}>+{asArray(profile?.skills).length - 8}</span>
              )}
            </div>
          )}
        </div>

        {/* Sticky Tabs */}
        <div style={{
          display: 'flex', borderBottom: '1px solid #f1f5f9', flexShrink: 0,
          position: 'sticky', top: 0, background: 'white', zIndex: 10
        }}>
          {tabs.map(tab => (
            <button key={tab.key} onClick={() => setActiveTab(tab.key)} style={{
              flex: 1, padding: '14px 4px', border: 'none', background: 'none',
              fontSize: 13, fontWeight: activeTab === tab.key ? 800 : 600,
              color: activeTab === tab.key ? '#6366f1' : '#94a3b8',
              borderBottom: activeTab === tab.key ? '3px solid #6366f1' : '3px solid transparent',
              cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
              transition: 'all 0.2s'
            }}>
              <span>{tab.icon}</span>
              <span>{tab.label}</span>
              {tab.count > 0 && (
                <span style={{
                  fontSize: 10, background: activeTab === tab.key ? '#eef2ff' : '#f1f5f9',
                  color: activeTab === tab.key ? '#6366f1' : '#94a3b8', padding: '1px 6px',
                  borderRadius: 10, fontWeight: 700
                }}>{tab.count}</span>
              )}
            </button>
          ))}
        </div>

        {/* Scrollable Content */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '16px 20px 24px' }}>
          {error && (
            <div style={{ marginBottom: 12, padding: '10px 12px', borderRadius: 12, background: '#fef2f2', border: '1px solid #fecaca', color: '#991b1b', fontSize: 12, fontWeight: 700 }}>
              {error}
            </div>
          )}
          {/* WORK TAB */}
          {activeTab === 'work' && (
            <>
              {completedJobs.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                  <div style={{ fontSize: 48, marginBottom: 12 }}>📷</div>
                  <h3 style={{ margin: 0, fontSize: 18, fontWeight: 700, color: '#1e293b' }}>No work photos yet</h3>
                  <p style={{ fontSize: 13, color: '#64748b', marginTop: 4 }}>This provider hasn't completed any jobs with photos.</p>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                  <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 4, scrollbarWidth: 'none' }}>
                    {workCategories.map((category) => {
                      const isActive = workCategoryFilter === category;
                      const label = category === 'all' ? 'All Categories' : category;
                      return (
                        <button
                          key={category}
                          onClick={() => setWorkCategoryFilter(category)}
                          style={{ border: 'none', borderRadius: 999, padding: '8px 12px', fontSize: 12, fontWeight: 700, cursor: 'pointer', whiteSpace: 'nowrap', background: isActive ? '#1e293b' : '#f1f5f9', color: isActive ? 'white' : '#475569' }}
                        >
                          {label}
                        </button>
                      );
                    })}
                  </div>
                  {filteredCompletedJobs.map(job => {
                    const beforeImages = job.jobDescriptionImages || [];
                    const afterImages = job.proofImages || [];
                    const hasPhotos = beforeImages.length > 0 || afterImages.length > 0;
                    return (
                      <div key={job._id} style={{
                        background: 'white', borderRadius: 20, border: '1px solid #f1f5f9',
                        boxShadow: '0 1px 3px rgba(0,0,0,0.04)', overflow: 'hidden'
                      }}>
                        {/* Card Header */}
                        <div style={{ padding: '14px 16px 10px' }}>
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                            <div style={{ flex: 1, minWidth: 0 }}>
                              <h4 style={{ margin: 0, fontSize: 15, fontWeight: 700, color: '#1e293b', lineHeight: 1.3 }}>{job.serviceId?.title || job.title || 'Completed Job'}</h4>
                              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 6, flexWrap: 'wrap' }}>
                                <span style={{ fontSize: 11, background: '#e2e8f0', color: '#334155', padding: '2px 8px', borderRadius: 10, fontWeight: 700 }}>{job.serviceId?.category || job.category || 'General'}</span>
                                <span style={{ fontSize: 11, color: '#94a3b8' }}>{job.completedAt ? new Date(job.completedAt).toLocaleDateString() : 'Recently'}</span>
                                {job.providerRating && (
                                  <span style={{ fontSize: 11, color: '#f59e0b', fontWeight: 700 }}>⭐ {job.providerRating}</span>
                                )}
                              </div>
                            </div>
                            <div style={{ fontSize: 16, fontWeight: 800, color: '#6366f1', flexShrink: 0 }}>R{job.randAmount || job.approvedAmount || job.budget || 0}</div>
                          </div>
                        </div>

                        {/* Photos */}
                        {hasPhotos && (
                          <div style={{ padding: '0 16px 12px' }}>
                            {beforeImages.length > 0 && (
                              <div style={{ marginBottom: 10 }}>
                                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
                                  <div style={{ fontSize: 12, fontWeight: 800, color: '#334155', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Before Work</div>
                                  <span style={{ fontSize: 11, fontWeight: 700, color: '#991b1b', background: '#fee2e2', padding: '2px 8px', borderRadius: 999 }}>{beforeImages.length} photos</span>
                                </div>
                                <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 6, scrollbarWidth: 'none' }}>
                                  {beforeImages.map((img, i) => (
                                    <button key={`b-${i}`} onClick={() => openGallery([...beforeImages, ...afterImages], i)} style={{ border: 'none', padding: 0, background: 'transparent', borderRadius: 14, overflow: 'hidden', minWidth: '88%', maxWidth: '88%', height: 190, flexShrink: 0, cursor: 'pointer', boxShadow: '0 2px 8px rgba(15, 23, 42, 0.12)' }}>
                                      <img src={img.url || img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => { e.target.onerror = null; e.target.src = PLACEHOLDER_IMG; }} />
                                    </button>
                                  ))}
                                </div>
                              </div>
                            )}
                            {afterImages.length > 0 && (
                              <div>
                                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
                                  <div style={{ fontSize: 12, fontWeight: 800, color: '#334155', textTransform: 'uppercase', letterSpacing: '0.04em' }}>After Work</div>
                                  <span style={{ fontSize: 11, fontWeight: 700, color: '#166534', background: '#dcfce7', padding: '2px 8px', borderRadius: 999 }}>{afterImages.length} photos</span>
                                </div>
                                <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 6, scrollbarWidth: 'none' }}>
                                  {afterImages.map((img, i) => (
                                    <button key={`a-${i}`} onClick={() => openGallery([...beforeImages, ...afterImages], beforeImages.length + i)} style={{ border: 'none', padding: 0, background: 'transparent', borderRadius: 14, overflow: 'hidden', minWidth: '88%', maxWidth: '88%', height: 190, flexShrink: 0, cursor: 'pointer', boxShadow: '0 2px 8px rgba(15, 23, 42, 0.12)' }}>
                                      <img src={img.url || img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => { e.target.onerror = null; e.target.src = PLACEHOLDER_IMG; }} />
                                    </button>
                                  ))}
                                </div>
                              </div>
                            )}
                          </div>
                        )}

                        {/* Review */}
                        {job.providerReview && (
                          <div style={{ padding: '0 16px 14px' }}>
                            <div style={{ background: '#f8fafc', borderRadius: 14, padding: 12, fontSize: 13, color: '#475569' }}>
                              <span style={{ fontSize: 10, color: '#94a3b8', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.04em' }}>Client Review</span>
                              <p style={{ margin: '4px 0 0', fontStyle: 'italic', lineHeight: 1.5 }}>"{job.providerReview}"</p>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </>
          )}

          {/* SERVICES TAB */}
          {activeTab === 'services' && (
            <>
              {services.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                  <div style={{ fontSize: 48, marginBottom: 12 }}>💼</div>
                  <h3 style={{ margin: 0, fontSize: 18, fontWeight: 700, color: '#1e293b' }}>No services</h3>
                  <p style={{ fontSize: 13, color: '#64748b', marginTop: 4 }}>This provider isn't offering any services right now.</p>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                  {services.map(service => (
                    <div key={service._id} style={{
                      background: 'white', borderRadius: 20, border: '1px solid #f1f5f9',
                      boxShadow: '0 1px 3px rgba(0,0,0,0.04)', padding: 16
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <h4 style={{ margin: 0, fontSize: 15, fontWeight: 700, color: '#1e293b' }}>{service.title}</h4>
                          <div style={{ display: 'flex', gap: 6, marginTop: 6, flexWrap: 'wrap' }}>
                            <span style={{ fontSize: 11, background: '#dbeafe', color: '#1d4ed8', padding: '2px 8px', borderRadius: 10, fontWeight: 600 }}>{service.category}</span>
                            <span style={{ fontSize: 11, background: '#f0fdf4', color: '#166534', padding: '2px 8px', borderRadius: 10, fontWeight: 600 }}>
                              {service.pricingType === 'quote' ? '📋 Quote' : '💵 Fixed'}
                            </span>
                          </div>
                        </div>
                        <div style={{ fontSize: 18, fontWeight: 800, color: '#6366f1', flexShrink: 0 }}>
                          {service.pricingType === 'quote' ? 'Custom' : `R${service.randAmount}`}
                        </div>
                      </div>
                      <p style={{ fontSize: 13, color: '#475569', margin: '10px 0 0', lineHeight: 1.5 }}>{service.description}</p>
                      {asArray(service.images).length > 0 && (
                        <div style={{ display: 'flex', gap: 6, marginTop: 10 }}>
                          {asArray(service.images).slice(0, 4).map((img, i) => (
                            <img key={i} src={img.url || img} alt="" style={{ width: 56, height: 56, borderRadius: 12, objectFit: 'cover', cursor: 'pointer' }} onClick={() => openGallery(asArray(service.images), i)} />
                          ))}
                          {asArray(service.images).length > 4 && <span style={{ fontSize: 12, color: '#94a3b8', alignSelf: 'center' }}>+{asArray(service.images).length - 4}</span>}
                        </div>
                      )}
                      <div style={{ display: 'flex', gap: 12, marginTop: 10, fontSize: 12, color: '#64748b' }}>
                        <span>✅ <strong>{service.completedJobsCount || 0}</strong> done</span>
                        <span>⭐ <strong>{service.averageRating || '5.0'}</strong></span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {/* POSTED JOBS TAB */}
          {activeTab === 'posted' && (
            <>
              {postedJobs.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                  <div style={{ fontSize: 48, marginBottom: 12 }}>📋</div>
                  <h3 style={{ margin: 0, fontSize: 18, fontWeight: 700, color: '#1e293b' }}>No posted jobs</h3>
                  <p style={{ fontSize: 13, color: '#64748b', marginTop: 4 }}>This user hasn't posted any jobs yet.</p>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                  {postedJobs.map(job => {
                    const beforeImages = normalizeImages(job.images);
                    const afterImages = normalizeImages(job.workProofPhotos);
                    const hasPhotos = beforeImages.length > 0 || afterImages.length > 0;
                    const providerNameDisplay = job.acceptedApplicationId?.applicantId?.name || 'Unknown provider';
                    return (
                      <div key={job._id} style={{
                        background: 'white', borderRadius: 20, border: '1px solid #f1f5f9',
                        boxShadow: '0 1px 3px rgba(0,0,0,0.04)', overflow: 'hidden'
                      }}>
                        <div style={{ padding: '14px 16px 10px' }}>
                          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 8 }}>
                            <div style={{ flex: 1, minWidth: 0 }}>
                              <h4 style={{ margin: 0, fontSize: 15, fontWeight: 700, color: '#1e293b', lineHeight: 1.3 }}>{job.title}</h4>
                              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 6, flexWrap: 'wrap' }}>
                                <span style={{ fontSize: 11, background: '#f1f5f9', color: '#475569', padding: '2px 8px', borderRadius: 10, fontWeight: 600 }}>{job.category}</span>
                                <span style={{ fontSize: 11, color: '#94a3b8' }}>by <strong>{providerNameDisplay}</strong></span>
                                <span style={{ fontSize: 11, color: '#94a3b8' }}>{job.completedAt ? new Date(job.completedAt).toLocaleDateString() : 'Recently'}</span>
                              </div>
                            </div>
                            <div style={{ fontSize: 16, fontWeight: 800, color: '#6366f1', flexShrink: 0 }}>R{job.approvedAmount || job.budget || 0}</div>
                          </div>
                        </div>
                        {hasPhotos && (
                          <div style={{ padding: '0 16px 14px' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 6 }}>
                              {beforeImages.slice(0, 3).map((img, i) => (
                                <div key={`b-${i}`} style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', aspectRatio: '1' }}>
                                  <img src={img.url || img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', cursor: 'pointer' }} onClick={() => openGallery([...beforeImages, ...afterImages], i)} />
                                  <span style={{ position: 'absolute', top: 6, left: 6, fontSize: 9, fontWeight: 800, color: 'white', background: 'rgba(239,68,68,0.85)', padding: '2px 6px', borderRadius: 10, textTransform: 'uppercase' }}>Before</span>
                                </div>
                              ))}
                              {afterImages.slice(0, Math.max(1, 6 - beforeImages.length)).map((img, i) => (
                                <div key={`a-${i}`} style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', aspectRatio: '1' }}>
                                  <img src={img.url || img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', cursor: 'pointer' }} onClick={() => openGallery([...beforeImages, ...afterImages], beforeImages.length + i)} />
                                  <span style={{ position: 'absolute', top: 6, left: 6, fontSize: 9, fontWeight: 800, color: 'white', background: 'rgba(34,197,94,0.85)', padding: '2px 6px', borderRadius: 10, textTransform: 'uppercase' }}>After</span>
                                </div>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </>
          )}
        </div>

        {/* Bottom Close */}
        <div style={{ padding: '12px 20px', borderTop: '1px solid #f1f5f9', display: 'flex', justifyContent: 'center', flexShrink: 0, background: 'white' }}>
          <button onClick={onClose} style={{ padding: '10px 24px', borderRadius: 12, border: 'none', fontSize: 14, fontWeight: 700, cursor: 'pointer', background: '#f1f5f9', color: '#475569' }}>
            ✕ Close
          </button>
        </div>
      </div>

      {galleryPhotos.length > 0 && (
        <PhotoGallery
          photos={galleryPhotos}
          startIndex={galleryStartIndex}
          onClose={() => {
            setGalleryPhotos([]);
            setGalleryStartIndex(0);
          }}
        />
      )}
    </div>
  );
}

export default ProviderPortfolio;
